export function resourceFromAttributes(attributes = {}) {
  return {
    attributes,
    merge(other = {}) {
      return resourceFromAttributes({
        ...attributes,
        ...(other.attributes ?? {}),
      })
    },
  }
}

function createDetector() {
  return {
    detect() {
      return resourceFromAttributes()
    },
  }
}

export const envDetector = createDetector()
export const hostDetector = createDetector()
export const osDetector = createDetector()
